1	using System.Diagnostics;
2	using Microsoft.AspNetCore.Mvc;
3	using HttpResults = Microsoft.AspNetCore.Http.Results;
4	
5	namespace TodoApi.Infrastructure.Extensions;
6	
7	public static class ResultExtensions
8	{
9	    private static int GetStatusCode(ErrorDefinition definition) =>
10	        definition switch
11	        {
12	            ErrorDefinition.NotFound => StatusCodes.Status404NotFound,
13	            ErrorDefinition.Validation => StatusCodes.Status400BadRequest,
14	            ErrorDefinition.Conflict => StatusCodes.Status409Conflict,
15	            ErrorDefinition.Unauthorized => StatusCodes.Status401Unauthorized,
16	            _ => StatusCodes.Status500InternalServerError,
17	        };
18	
19	    private static string GetProblemType(ErrorDefinition definition) =>
20	        definition switch
21	        {
22	            ErrorDefinition.NotFound => "https://tools.ietf.org/html/rfc9110#section-15.5.5",
23	            ErrorDefinition.Validation => "https://tools.ietf.org/html/rfc9110#section-15.5.1",
24	            ErrorDefinition.Conflict => "https://tools.ietf.org/html/rfc9110#section-15.5.10",
25	            ErrorDefinition.Unauthorized => "https://tools.ietf.org/html/rfc9110#section-15.5.2",
26	            _ => "https://tools.ietf.org/html/rfc9110#section-15.6.1",
27	        };
28	
29	    private static string GetTitle(ErrorDefinition definition) =>
30	        definition switch
31	        {
32	            ErrorDefinition.NotFound => "Resource Not Found",
33	            ErrorDefinition.Validation => "Validation Error",
34	            ErrorDefinition.Conflict => "Conflict",
35	            ErrorDefinition.Unauthorized => "Unauthorized",
36	            ErrorDefinition.Error => "Internal Server Error",
37	            _ => "An error occurred",
38	        };
39	
40	    public static IResult Match<T>(
41	        this Result<T> result,
42	        Func<T, IResult> onSuccess,
43	        Func<Result, IResult>? onFailure = null
44	    )
45	    {
46	        ArgumentNullException.ThrowIfNull(result);
47	        ArgumentNullException.ThrowIfNull(onSuccess);
48	
49	        return result.IsSuccess
50	            ? onSuccess(result.GetValue)
51	            : (onFailure ?? (r => r.ToProblemDetails()))(result);
52	    }
53	
54	    public static IResult ToOk<T>(this Result<T> result, Func<T, object>? mapper = null)
55	    {
56	        return result.Match(onSuccess: value => HttpResults.Ok(mapper?.Invoke(value) ?? value));
57	    }
58	
59	    public static IResult ToCreated<T>(
60	        this Result<T> result,
61	        string uri,
62	        Func<T, object>? mapper = null
63	    )
64	    {
65	        return result.Match(onSuccess: value =>
66	            HttpResults.Created(uri, mapper?.Invoke(value) ?? value)
67	        );
68	    }
69	
70	    public static IResult ToCreated<T>(
71	        this Result<T> result,
72	        Func<T, string> uriFactory,
73	        Func<T, object>? mapper = null
74	    )
75	    {
76	        ArgumentNullException.ThrowIfNull(uriFactory);
77	
78	        return result.Match(onSuccess: value =>
79	            HttpResults.Created(uriFactory(value), mapper?.Invoke(value) ?? value)
80	        );
81	    }
82	
83	    public static IResult ToAccepted<T>(
84	        this Result<T> result,
85	        string uri,
86	        Func<T, object>? mapper = null
87	    )
88	    {
89	        return result.Match(onSuccess: value =>
90	            HttpResults.Accepted(uri, mapper?.Invoke(value) ?? value)
91	        );
92	    }
93	
94	    public static IResult ToNoContent<T>(this Result<T> result)
95	    {
96	        return result.Match(onSuccess: _ => HttpResults.NoContent());
97	    }
98	
99	    public static IResult ToNoContent(this Result result)
100	    {
101	        ArgumentNullException.ThrowIfNull(result);
102	
103	        return result.IsSuccess ? HttpResults.NoContent() : result.ToProblemDetails();
104	    }
105	
106	    public static IResult ToProblemDetails(this Result result)
107	    {
108	        ArgumentNullException.ThrowIfNull(result);
109	
110	        if (result.IsSuccess)
111	        {
112	            throw new InvalidOperationException(
113	                "Cannot create problem details from a successful result."
114	            );
115	        }
116	
117	        var error = result.Error;
118	        var statusCode = GetStatusCode(error.Definition);
119	        var traceId = Activity.Current?.Id;
120	
121	        if (error.Definition == ErrorDefinition.Validation)
122	        {
123	            return HttpResults.Problem(BuildValidationProblem(error, statusCode, traceId));
124	        }
125	
126	        var problemDetails = new ProblemDetails
127	        {
128	            Type = GetProblemType(error.Definition),
129	            Title = GetTitle(error.Definition),
130	            Status = statusCode,
131	            Detail = error.Description,
132	        };
133	
134	        problemDetails.Extensions["code"] = error.Code;
135	        if (traceId is not null)
136	        {
137	            problemDetails.Extensions["traceId"] = traceId;
138	        }
139	
140	        return HttpResults.Problem(problemDetails);
141	    }
142	
143	    private static ValidationProblemDetails BuildValidationProblem(
144	        ErrorResult error,
145	        int statusCode,
146	        string? traceId
147	    )
148	    {
149	        var errors =
150	            error.Metadata is { } metadata
151	            && metadata.TryGetValue("Errors", out var raw)
152	            && raw is Dictionary<string, string[]> map
153	                ? map
154	                : new Dictionary<string, string[]>(StringComparer.Ordinal);
155	
156	        var problem = new ValidationProblemDetails(errors)
157	        {
158	            Type = GetProblemType(error.Definition),
159	            Title = GetTitle(error.Definition),
160	            Status = statusCode,
161	            Detail = error.Description,
162	        };
163	
164	        problem.Extensions["code"] = error.Code;
165	        if (traceId is not null)
166	        {
167	            problem.Extensions["traceId"] = traceId;
168	        }
169	
170	        return problem;
171	    }
172	}
